// Configuramos la zona horaria de Bogotá
const opcionesDia = {
  timeZone: 'America/Bogota',
  weekday: 'long'
};
const hoyEnBogota = new Date().toLocaleDateString('es-ES', opcionesDia);
const diaCapitalizado = hoyEnBogota.charAt(0).toUpperCase() + hoyEnBogota.slice(1);
const opcionesHora = {
  timeZone: 'America/Bogota',
  hour: '2-digit',
  minute: '2-digit',
  second: '2-digit',
  hour12: false
};
const ahora = new Date();
const hace1min = new Date(ahora.getTime() - 1 * 60 * 1000);
const en1min = new Date(ahora.getTime() + 1 * 60 * 1000);
const horaBogota = ahora.toLocaleTimeString('es-ES', opcionesHora);
const horaMenos30 = hace1min.toLocaleTimeString('es-ES', opcionesHora);
const horaMas120 = en1min.toLocaleTimeString('es-ES', opcionesHora);

// Calcular día del mes y fecha ISO en zona Bogotá
const fechaEnBogota = new Date(ahora.toLocaleString("en-US", { timeZone: 'America/Bogota' }));
const diaDelMes = fechaEnBogota.getDate();
const anio = fechaEnBogota.getFullYear();
const mesNum = String(fechaEnBogota.getMonth() + 1).padStart(2, '0');
const diaNum = String(fechaEnBogota.getDate()).padStart(2, '0');
const fechaHoyISO = `${anio}-${mesNum}-${diaNum}`;

return [
  {
    json: {
      dia: diaCapitalizado,
      hora: horaBogota,
      horaMenos30: horaMenos30,
      horaMas120: horaMas120,
      diaDelMes: diaDelMes,
      fechaHoyISO: fechaHoyISO,
      zonaHoraria: 'America/Bogota'
    }
  }
];

