  'El Salvador': 'America/El_Salvador',
  'Nicaragua': 'America/Managua',
  'Puerto Rico': 'America/Puerto_Rico',
  'Estados Unidos': 'America/Los_Angeles'
};

const offsetVsColombia = {
  'America/Bogota': 0,
  'America/Lima': 0,
  'America/Guayaquil': 0,
  'America/Panama': 0,
  'America/El_Salvador': 0,
  'America/Costa_Rica': -1,
  'America/Mexico_City': -1,
  'America/Guatemala': -1,
  'America/Tegucigalpa': -1,
