  'America/La_Paz': 1,
  'America/Santiago': 1,
  'America/Asuncion': 2,
  'America/Puerto_Rico': 1,
  'America/Montevideo': 2,
  'America/Argentina/Buenos_Aires': 2
};

function convertirHoraColombiaAZona(horaColombiaStr, zonaDestino) {
  if (!horaColombiaStr) return null;
  try {
    const [h, m, s] = horaColombiaStr.split(':').map(Number);
    const offset = offsetVsColombia[zonaDestino] !== undefined ? offsetVsColombia[zonaDestino] : 0;
    const offsetHoras = Math.floor(offset);
    const offsetMinutos = Math.round((offset - offsetHoras) * 60);
    let horaFinal = h + offsetHoras;
    let minutosFinal = m + offsetMinutos;
    if (minutosFinal >= 60) { horaFinal += 1; minutosFinal -= 60; }
    else if (minutosFinal < 0) { horaFinal -= 1; minutosFinal += 60; }
    if (horaFinal >= 24) horaFinal -= 24;
    if (horaFinal < 0) horaFinal += 24;
    return `${String(horaFinal).padStart(2, '0')}:${String(minutosFinal).padStart(2, '0')}:${String(s).padStart(2, '0')}`;
  } catch (error) {
    console.log(`Error convirtiendo hora: ${horaColombiaStr}`, error);
    return null;
  }
}

function obtenerZonaHoraria(pais) {
  return paisAZonaHoraria[pais] || 'America/Bogota';
}

function obtenerFechaHoraPorZona(zonaHoraria) {
  const today = new Date();
  const fechaZona = new Date(today.toLocaleString("en-US", { timeZone: zonaHoraria }));
  return fechaZona;
}

function parsearHoraSolo(horaStr, fechaReferencia) {
  if (!horaStr) return null;
  try {
    const [horas, minutos, segundos] = horaStr.split(':');
    const fechaHoy = new Date(fechaReferencia);
    fechaHoy.setHours(parseInt(horas));
    fechaHoy.setMinutes(parseInt(minutos));
    fechaHoy.setSeconds(parseInt(segundos || 0));
    fechaHoy.setMilliseconds(0);
    return fechaHoy;
  } catch (error) {
    console.log(`Error parseando hora: ${horaStr}`, error);
    return null;
  }
}

function estaEnRango4Minutos(fechaObjetivo, fechaActual) {
  if (!fechaObjetivo) return false;
  const diferenciaMilisegundos = fechaObjetivo.getTime() - fechaActual.getTime();
  const diferenciaMinutos = diferenciaMilisegundos / (1000 * 60);
  console.log(`Comparando: ${fechaObjetivo.toLocaleString()} vs ${fechaActual.toLocaleString()}`);
  console.log(`Diferencia en minutos: ${diferenciaMinutos}`);
  return diferenciaMinutos >= -2 && diferenciaMinutos <= 2;
}

let countOriginal = inputData.length;
let countFiltradosFechaDia = 0;
