    dentroDelRango = !datos.fecha_inicio || !datos.fecha_termino ||
      (fechaHoyString >= datos.fecha_inicio && fechaHoyString <= datos.fecha_termino);
    diaValido = datos.dia_mes === fechaHoraPais.getDate();
  } else if (datos.tipo_lanzamiento === 'fecha_unica') {
    // Para fecha única: verificar que la fecha exacta coincide con hoy
    diaValido = datos.fecha_lanzamiento === fechaHoyString;
    dentroDelRango = true;
  }

  console.log(`Tipo lanzamiento: ${datos.tipo_lanzamiento}`);
  console.log(`dia_mes: ${datos.dia_mes}, diaHoy: ${fechaHoraPais.getDate()}`);
  console.log(`fecha_lanzamiento: ${datos.fecha_lanzamiento}, fechaHoy: ${fechaHoyString}`);
  console.log(`diaValido: ${diaValido}, dentroDelRango: ${dentroDelRango}`);

  const pasoFecha = dentroDelRango;
  const pasoDia = diaValido;
  const pasoAmbos = pasoFecha && pasoDia;

  return {
    ...item,
    json: datos,
    fechaHoraPais: fechaHoraPais,
    zonaHoraria: zonaHoraria,
