});

const datosFiltradosPorFechaYDia = datosConDebug.filter(i => i.debug.pasoFecha && i.debug.pasoDia);
countFiltradosFechaDia = datosFiltradosPorFechaYDia.length;
console.log(`Elementos filtrados por fecha y día: ${countFiltradosFechaDia}`);

