const resultados = datosRango4Min.map(item => {
  const datos = item.json;

  function getVideoId(url) {
    if (!url) return { id: null, type: null };
    const youtubeRegex = /(?:youtube\.com\/watch\?v=|youtu\.be\/)([^&\n?#]+)/;
    const youtubeMatch = url.match(youtubeRegex);
    if (youtubeMatch) return { id: youtubeMatch[1], type: 'youtube' };
    const driveRegex = /\/file\/d\/([a-zA-Z0-9_-]+)/;
    const driveMatch = url.match(driveRegex);
    if (driveMatch) return { id: driveMatch[1], type: 'drive' };
    return { id: null, type: null };
  }

  function getVideoThumbnails(videoInfo) {
    if (!videoInfo.id) return null;
    if (videoInfo.type === 'youtube') {
      return {
        default: `https://img.youtube.com/vi/${videoInfo.id}/default.jpg`,
        medium: `https://img.youtube.com/vi/${videoInfo.id}/mqdefault.jpg`,
        high: `https://img.youtube.com/vi/${videoInfo.id}/hqdefault.jpg`,
        standard: `https://img.youtube.com/vi/${videoInfo.id}/sddefault.jpg`,
        maxres: `https://img.youtube.com/vi/${videoInfo.id}/maxresdefault.jpg`
      };
    }
    if (videoInfo.type === 'drive') {
      return {
        preview: `https://drive.google.com/thumbnail?id=${videoInfo.id}`,
        direct: `https://drive.google.com/uc?id=${videoInfo.id}`,
        view: `https://drive.google.com/file/d/${videoInfo.id}/view`
      };
    }
    return null;
  }

  function procesarVariables(texto, datosItem) {
    if (!texto) return texto;
    let textoProcessado = texto;
    if (datosItem.link && textoProcessado.includes('${link}')) {
      textoProcessado = textoProcessado.replace(/\$\{link\}/g, datosItem.link);
    }
    if (datosItem.youtube_url && textoProcessado.includes('${youtubeUrl}')) {
      textoProcessado = textoProcessado.replace(/\$\{youtubeUrl\}/g, datosItem.youtube_url);
    }
    return textoProcessado;
  }

  function validarYProcesarImagen(imagenUrl) {
    if (!imagenUrl || imagenUrl.trim() === '') {
      return { tieneImagen: false, imagenUrl: null, esGoogleDrive: false, esUrlValida: false };
    }
    const urlLimpia = imagenUrl.trim();
    const esGoogleDrive = urlLimpia.includes('drive.google.com') || urlLimpia.includes('drive.usercontent.google.com');
    const esUrlValida = /^https?:\/\/.+/.test(urlLimpia);
    return { tieneImagen: true, imagenUrl: urlLimpia, esGoogleDrive, esUrlValida };
  }

  const videoId = getVideoId(datos.youtube_url);
  const youtubeThumbnail = getVideoThumbnails(videoId);
  const mensajeProcesado = procesarVariables(datos.mensaje_x_dia, datos);
  const textoProcesado = procesarVariables(datos.texto_video, datos);
  const imagenProcesada = validarYProcesarImagen(datos.imagen_url);
  const imagenTextoProcesado = procesarVariables(datos.imagen_texto, datos);

  const numeroDestinatario = [];
  if (datos.destinatario_persona_grupo && datos.destinatario_persona_grupo.trim() !== '') {
    numeroDestinatario.push(datos.destinatario_persona_grupo.trim());
  }

  const tipoDestinatario = numeroDestinatario.length === 0 ? 'sin_destinatario' : 'grupo';

  let tipoContenido = 'solo_texto';
  if (imagenProcesada.tieneImagen && datos.youtube_url) {
    tipoContenido = 'imagen_y_video';
  } else if (imagenProcesada.tieneImagen) {
    tipoContenido = 'imagen';
  } else if (datos.youtube_url) {
    tipoContenido = 'video';
  }

  const fechaHoraPaisItem = item.fechaHoraPais;
  const zonaHorariaItem = item.zonaHoraria;

  return {
    json: {
      fechaActualPais: fechaHoraPaisItem.toISOString(),
      horaConfiguracion: datos.hora_colombia || datos.hora,
      zonaHoraria: zonaHorariaItem,
      pais: datos.admin_cpl_pais,
      tipo_lanzamiento: datos.tipo_lanzamiento,
      dia_mes: datos.dia_mes,
      fecha_lanzamiento: datos.fecha_lanzamiento,
      id: datos.id,
      youtubeUrl: datos.youtube_url,
      videoId: videoId,
      youtubeThumbnail: youtubeThumbnail,
      mensajePorDia: mensajeProcesado,
      textThumbnail: textoProcesado,
      imagen: imagenProcesada.imagenUrl,
      imagenTexto: imagenTextoProcesado,
      tieneImagen: imagenProcesada.tieneImagen,
      esImagenGoogleDrive: imagenProcesada.esGoogleDrive,
      esImagenUrlValida: imagenProcesada.esUrlValida,
      audioUrl: datos.audio_url,
      audioTexto: datos.audio_texto,
      tieneAudio: !!(datos.audio_url),
      tipoCpl: datos.tipo_cpl,
      destinatarioGrupo: datos.destinatario_persona_grupo,
      numeroDestinatario: numeroDestinatario,
