      tieneContenido: !!(mensajeProcesado || datos.youtube_url || imagenProcesada.tieneImagen || datos.audio_url),
      tieneDestinatario: numeroDestinatario.length > 0,
      datosOriginales: datos
    },
    debug: item.debug
  };
});

