}

return filteredResults;

// Filtra y procesa URLs de video (Google Drive, OneDrive, YouTube)

function detectVideoUrlType(url) {
  if (!url || typeof url !== 'string') return 'unknown';
  if (/drive\.google\.com/.test(url)) return 'drive';
  if (/1drv\.ms/.test(url) || /onedrive\.live\.com/.test(url) || /sharepoint\.com/.test(url)) return 'onedrive';
  if (/youtube\.com|youtu\.be/.test(url)) return 'youtube';
  return 'unknown';
}

function extractDriveFileId(url) {
  if (!url || typeof url !== 'string') return null;
  const match1 = url.match(/\/file\/d\/([a-zA-Z0-9_-]+)/);
  if (match1) return match1[1];
  const match2 = url.match(/[?&]id=([a-zA-Z0-9_-]+)/);
  if (match2) return match2[1];
  return null;
}

function convertOneDriveUrl(url) {
  if (!url || typeof url !== 'string') return url;
  if (url.includes('download=1')) return url;
  return url.includes('?') ? url + '&download=1' : url + '?download=1';
}

function processVideoUrl(url) {
  const type = detectVideoUrlType(url);
  let processedUrl = url;
  let videoId = { id: null, type: null };
  let youtubeThumbnail = { preview: null, direct: null, view: null };

  if (type === 'drive') {
    const fileId = extractDriveFileId(url);
    processedUrl = `https://drive.google.com/uc?export=download&id=${fileId}`;
    videoId = { id: fileId, type: 'drive' };
    youtubeThumbnail = {
      preview: `https://drive.google.com/thumbnail?id=${fileId}`,
      direct: `https://drive.google.com/uc?id=${fileId}`,
      view: `https://drive.google.com/file/d/${fileId}/view`
    };
  } else if (type === 'onedrive') {
    const directUrl = convertOneDriveUrl(url);
    processedUrl = directUrl;
    videoId = { id: url, type: 'onedrive' };
    youtubeThumbnail = { preview: null, direct: directUrl, view: url };
  } else if (type === 'youtube') {
    const ytMatch = url.match(/(?:youtube\.com\/watch\?v=|youtu\.be\/)([a-zA-Z0-9_-]+)/);
    const ytId = ytMatch ? ytMatch[1] : null;
    processedUrl = url;
    videoId = { id: ytId, type: 'youtube' };
    youtubeThumbnail = {
      preview: ytId ? `https://img.youtube.com/vi/${ytId}/hqdefault.jpg` : null,
      direct: url,
      view: url
    };
  }

  return { processedUrl, videoId, youtubeThumbnail };
}

